  // Construct the bash command with proper escaping
  const command = `grep 'ERROR' '${escapedLogFilePath}' | tail -n 100 | awk '{print $1,$2,$0}' | sort | tail -n ${escapedCount}`;

  try {
    // Execute the command using shelljs
    const result = shell.exec(command, { silent: true });

    // Check for command execution errors
    if (result.code !== 0 && result.code !== 1) {
      // code 1 is acceptable (no matches found by grep)
      throw new Error(`Command execution failed with code ${result.code}: ${result.stderr}`);
    }

    // Parse the output into an array of lines, filtering empty lines
    const output = result.stdout.trim();
    if (!output) {
      return [];
    }

    const lines = output.split('\n').filter(line => line.length > 0);
    return lines;
  } catch (error) {
    throw new Error(`Failed to extract error logs: ${error.message}`);
  }
}

module.exports = { extractRecentErrors };
